ps.pstext:
if !IsFeatureImplemented(FEAT_SVE_SM4) then EndOfDecode(Decode_UNDEF); end;
let m : integer = UInt(Zm);
let dn : integer = UInt(Zdn);

CheckNonStreamingSVEEnabled();
let VL : integer{} = CurrentVL();
let segments : integer = VL DIV 128;
let operand1 : bits(VL) = Z{}(dn);
let operand2 : bits(VL) = Z{}(m);
var result : bits(VL);

for s = 0 to segments-1 do
    let key : bits(128) = operand2[s*:128];
    var intval : bits(32);
    var roundresult : bits(128) = operand1[s*:128];
    var roundkey : bits(32);

    for index = 0 to 3 do
        roundkey = key[index*:32];
        intval = roundresult[127:96] XOR roundresult[95:64] XOR roundresult[63:32] XOR roundkey;

        for i = 0 to 3 do
            intval[i*:8]  = Sbox(intval[i*:8]);
        end;

        intval = (intval XOR
                  ROL(intval, 2) XOR
                  ROL(intval, 10) XOR
                  ROL(intval, 18) XOR
                  ROL(intval, 24));
        intval = intval XOR roundresult[31:0];

        roundresult[31:0] = roundresult[63:32];
        roundresult[63:32] = roundresult[95:64];
        roundresult[95:64] = roundresult[127:96];
        roundresult[127:96] = intval;
    end;

    result[s*:128] = roundresult;
end;

Z{VL}(dn) = result;
